module address_generator #(
    parameter ARRAY_WIDTH = 8,
    parameter MEM_LATENCY = 0  // 0 = behavioral (async), 1+ = SRAM cycles
)(
    input  wire        clk,
    input  wire        rst_n,
    input  wire        enable,
    input  wire        mode,
    input  wire [15:0] cfg_img_width,
    input  wire [3:0]  cfg_kernel_size,
    input  wire [15:0] start_row,
    input  wire [15:0] start_col,

    output reg  [15:0] mem_addr,
    input  wire [31:0] mem_rd_data,

    output reg  [ARRAY_WIDTH*8-1:0] out_data,
    output reg         out_valid,
    output reg         done
);

    reg [2:0] state;
    localparam IDLE = 3'd0;
    localparam FETCH_WEIGHTS = 3'd1;
    localparam PRE_FETCH     = 3'd2; // New state
    localparam FETCH_INPUTS  = 3'd3;
    localparam DONE_STATE    = 3'd4;

    reg [3:0] weight_row_count;
    reg       weight_half_loaded;
    reg [31:0] weight_buffer_lower;

    reg [7:0] fifo_mem [ARRAY_WIDTH-1:0][15:0];
    reg [ARRAY_WIDTH*4-1:0] fifo_wr_ptr;      // Flattened ARRAY_WIDTHx4
    reg [ARRAY_WIDTH*4-1:0] fifo_rd_ptr;      // Flattened ARRAY_WIDTHx4
    reg [ARRAY_WIDTH*5-1:0] fifo_count;       // Flattened ARRAY_WIDTHx5

    reg [3:0] fetch_row_idx;
    reg [ARRAY_WIDTH*16-1:0] current_col;     // Flattened ARRAY_WIDTHx16

    // active_delay_counter needs to hold values up to ARRAY_WIDTH-1 (1-cycle skew).
    // Width = $clog2(ARRAY_WIDTH).
    localparam CNT_WIDTH = $clog2(ARRAY_WIDTH);

    reg [ARRAY_WIDTH*CNT_WIDTH-1:0] active_delay_counter; // Flattened ARRAY_WIDTHxCNT_WIDTH
    reg [ARRAY_WIDTH-1:0]  row_active;           // Flattened ARRAY_WIDTHx1

    /* verilator lint_off UNUSEDSIGNAL */
    wire [3:0] kernel_dim = cfg_kernel_size + 1;
    /* verilator lint_on UNUSEDSIGNAL */

    // Memory request pipeline (extended for SRAM latency)
    reg [2:0] mem_req_row_pipe;
    reg       mem_req_valid_pipe;
    reg [2:0] mem_req_row_pipe2;
    reg       mem_req_valid_pipe2;

    // Weight fetch wait counter for SRAM latency
    reg [2:0] weight_wait_cnt;

    reg can_fire;

    // Combinational loop variable
    integer i_comb;
    always @(*) begin
        can_fire = 1;
        for (i_comb=0; i_comb<ARRAY_WIDTH; i_comb=i_comb+1) begin
            // Block only if active AND empty AND NOT done fetching
            if (row_active[i_comb] && fifo_count[i_comb*5 +: 5] == 0 && current_col[i_comb*16 +: 16] < cfg_img_width) can_fire = 0;
        end
    end

    // Address Calculation Wire (17-bit to prevent overflow, only lower 16 bits used)
    reg [15:0] next_mem_addr;
    /* verilator lint_off UNUSEDSIGNAL */
    wire [16:0] addr_calc_tmp = 17'h1000 + ({1'b0, start_row} + {13'd0, fetch_row_idx}) * {1'b0, cfg_img_width} + ({1'b0, current_col[fetch_row_idx*16 +: 16]} >> 2);
    /* verilator lint_on UNUSEDSIGNAL */
    always @(*) begin
        next_mem_addr = addr_calc_tmp[15:0];
    end

    // Sequential loop variable
    integer i_seq;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
            mem_addr <= 0;
            out_data <= 0;
            out_valid <= 0;
            done <= 0;
            weight_row_count <= 0;
            weight_half_loaded <= 0;
            weight_buffer_lower <= 0;
            fetch_row_idx <= 0;
            mem_req_valid_pipe <= 0;
            mem_req_row_pipe <= 0;
            mem_req_valid_pipe2 <= 0;
            mem_req_row_pipe2 <= 0;
            weight_wait_cnt <= 0;
            for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                fifo_wr_ptr[i_seq*4 +: 4] <= 0;
                fifo_rd_ptr[i_seq*4 +: 4] <= 0;
                fifo_count[i_seq*5 +: 5] <= 0;
                current_col[i_seq*16 +: 16] <= 0;
                active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] <= i_seq[CNT_WIDTH-1:0]; // 1-cycle skew
                row_active[i_seq] <= 0;
            end
        end else begin
            out_valid <= 0;
            done <= 0;
            mem_req_valid_pipe <= 0;

            // Pipeline stage 2 for SRAM latency
            mem_req_valid_pipe2 <= mem_req_valid_pipe;
            mem_req_row_pipe2 <= mem_req_row_pipe;

            // FIFO Write Update - use appropriate pipeline stage based on latency
            if (MEM_LATENCY >= 1) begin
                if (mem_req_valid_pipe2) begin
                    fifo_wr_ptr[mem_req_row_pipe2*4 +: 4] <= fifo_wr_ptr[mem_req_row_pipe2*4 +: 4] + 4;
                end
            end else begin
                if (mem_req_valid_pipe) begin
                    fifo_wr_ptr[mem_req_row_pipe*4 +: 4] <= fifo_wr_ptr[mem_req_row_pipe*4 +: 4] + 4;
                end
            end

            case (state)
                IDLE: begin
                    if (enable) begin
                        if (mode == 0) begin
                            state <= FETCH_WEIGHTS;
                            mem_addr <= 0;
                            weight_row_count <= 0;
                            weight_half_loaded <= 0;
                        end else begin
                            state <= PRE_FETCH;
                            for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                                current_col[i_seq*16 +: 16] <= start_col;
                                active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] <= i_seq[CNT_WIDTH-1:0]; // 1-cycle skew
                                row_active[i_seq] <= 0;
                                fifo_wr_ptr[i_seq*4 +: 4] <= 0;
                                fifo_rd_ptr[i_seq*4 +: 4] <= 0;
                                fifo_count[i_seq*5 +: 5] <= 0;
                            end
                            fetch_row_idx <= 0;
                        end
                    end
                end

                FETCH_WEIGHTS: begin
                    // Wait for SRAM latency before reading data
                    /* verilator lint_off UNSIGNED */
                    if (weight_wait_cnt < MEM_LATENCY) begin
                    /* verilator lint_on UNSIGNED */
                        weight_wait_cnt <= weight_wait_cnt + 1;
                    end else begin
                        weight_wait_cnt <= 0;
                        if (!weight_half_loaded) begin
                            weight_buffer_lower <= mem_rd_data;
                            mem_addr <= mem_addr + 1;
                            weight_half_loaded <= 1;
                        end else begin
                            out_data <= {{(ARRAY_WIDTH*8-64){1'b0}}, mem_rd_data, weight_buffer_lower}; 
                            out_valid <= 1;
                            mem_addr <= mem_addr + 1;
                            weight_half_loaded <= 0;

                            if (weight_row_count == ARRAY_WIDTH-1) begin
                                state <= DONE_STATE;
                            end else begin
                                weight_row_count <= weight_row_count + 1;
                            end
                        end
                    end
                end

                PRE_FETCH: begin
                    if (fetch_row_idx < ARRAY_WIDTH) begin
                         if (fifo_count[fetch_row_idx*5 +: 5] < 4 && current_col[fetch_row_idx*16 +: 16] < cfg_img_width) begin
                            mem_addr <= next_mem_addr;
                            mem_req_row_pipe <= fetch_row_idx[2:0];
                            mem_req_valid_pipe <= 1;
                            current_col[fetch_row_idx*16 +: 16] <= current_col[fetch_row_idx*16 +: 16] + 4;
                        end
                        fetch_row_idx <= fetch_row_idx + 1; 
                    end else begin
                        state <= FETCH_INPUTS;
                        fetch_row_idx <= 0;
                    end
                end

                FETCH_INPUTS: begin
                    // Fetch Request
                    if (fifo_count[fetch_row_idx*5 +: 5] < 12 && current_col[fetch_row_idx*16 +: 16] < cfg_img_width) begin
                        mem_addr <= next_mem_addr;
                        mem_req_row_pipe <= fetch_row_idx[2:0];
                        mem_req_valid_pipe <= 1;
                        current_col[fetch_row_idx*16 +: 16] <= current_col[fetch_row_idx*16 +: 16] + 4;
                    end
                    if (fetch_row_idx == ARRAY_WIDTH-1) fetch_row_idx <= 0;
                    else fetch_row_idx <= fetch_row_idx + 1;

                    // Output Logic
                    for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                        if (active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] > 0) begin
                            if (can_fire)
                                active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] <= active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] - 1;
                        end else begin
                            row_active[i_seq] <= 1;
                        end
                    end

                    if (can_fire) begin
                        out_valid <= 1;
                        for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                            if (row_active[i_seq] && fifo_count[i_seq*5 +: 5] > 0) begin
                                out_data[i_seq*8 +: 8] <= fifo_mem[i_seq][fifo_rd_ptr[i_seq*4 +: 4]];
                                fifo_rd_ptr[i_seq*4 +: 4] <= fifo_rd_ptr[i_seq*4 +: 4] + 1;
                            end else begin
                                out_data[i_seq*8 +: 8] <= 8'd0;
                            end
                        end
                    end
                    // Check for termination condition
                    if (all_rows_done) begin
                        state <= DONE_STATE;
                    end
                end

                DONE_STATE: begin
                    done <= 1;
                    if (!enable) state <= IDLE;
                end

                default: state <= IDLE;
            endcase

            // FIFO Count Update - use appropriate pipeline based on latency
            // Variables for latency-aware signals (moved outside for loop for Verilog compliance)
            begin : fifo_cnt_blk
                reg fifo_write_valid;
                reg [2:0] fifo_write_row;

                if (MEM_LATENCY >= 1) begin
                    fifo_write_valid = mem_req_valid_pipe2;
                    fifo_write_row = mem_req_row_pipe2;
                end else begin
                    fifo_write_valid = mem_req_valid_pipe;
                    fifo_write_row = mem_req_row_pipe;
                end

                for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                    if (fifo_write_valid && {29'd0, fifo_write_row} == i_seq && (state == FETCH_INPUTS || state == PRE_FETCH) && can_fire && row_active[i_seq]) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] + 3; // +4 written, -1 read
                    end else if (fifo_write_valid && {29'd0, fifo_write_row} == i_seq) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] + 4;
                    end else if (state == FETCH_INPUTS && can_fire && row_active[i_seq] && fifo_count[i_seq*5 +: 5] > 0) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] - 1;
                    end
                end
            end

            if (mem_req_valid_pipe) begin
                 // Debug removed
            end
            if (state == PRE_FETCH || state == FETCH_INPUTS) begin
                 // Debug removed
            end
        end
    end

    // Termination Check Logic
    reg all_rows_done;
    integer i_term;
    always @(*) begin
        all_rows_done = 1;
        for (i_term=0; i_term<ARRAY_WIDTH; i_term=i_term+1) begin
            if (current_col[i_term*16 +: 16] < cfg_img_width || fifo_count[i_term*5 +: 5] != 0) begin
                all_rows_done = 0;
            end
        end
    end

    // Note: Termination check is now handled inside main always block via all_rows_done
    // The main always block uses 'all_rows_done' to transition from FETCH_INPUTS to DONE_STATE

    // FIFO memory write - use delayed pipeline when MEM_LATENCY >= 1
    generate
        if (MEM_LATENCY >= 1) begin : gen_sram_fifo_write
            always @(posedge clk) begin
                if (mem_req_valid_pipe2) begin
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]]   <= mem_rd_data[7:0];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+1] <= mem_rd_data[15:8];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+2] <= mem_rd_data[23:16];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+3] <= mem_rd_data[31:24];
                end
            end
        end else begin : gen_behav_fifo_write
            always @(posedge clk) begin
                if (mem_req_valid_pipe) begin
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]]   <= mem_rd_data[7:0];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+1] <= mem_rd_data[15:8];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+2] <= mem_rd_data[23:16];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+3] <= mem_rd_data[31:24];
                end
            end
        end
    endgenerate

endmodule

