                    if (enable) begin
                        if (mode == 0) begin
                            state <= FETCH_WEIGHTS;
                            mem_addr <= 0;
                            weight_row_count <= 0;
                            weight_half_loaded <= 0;
                            tile_addr_counter <= 0;
                        end else begin
                            state <= PRE_FETCH;
                            tile_addr_counter <= 0;  // Reset for new tile
                            for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                                current_col[i_seq*16 +: 16] <= start_col;
                                active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] <= i_seq[CNT_WIDTH-1:0]; // 1-cycle skew
                                row_active[i_seq] <= 0;
                                fifo_wr_ptr[i_seq*4 +: 4] <= 0;
                                fifo_rd_ptr[i_seq*4 +: 4] <= 0;
                                fifo_count[i_seq*5 +: 5] <= 0;
                            end
                            fetch_row_idx <= 0;
                        end
                    end
                end

                FETCH_WEIGHTS: begin
                    // Load weights sequentially: 4 weights per word, ARRAY_WIDTH words per load
                    // For kernel_size x kernel_size kernel on ARRAY_WIDTH x ARRAY_WIDTH systolic array:
                    // - If kernel_size <= ARRAY_WIDTH: load all kernel rows in one pass
                    // - Memory layout: consecutive addresses, 4 weights packed per 32-bit word
                    // - Each kernel row occupies ceil(kernel_size/4) words, aligned to ARRAY_WIDTH addresses

                    /* verilator lint_off UNSIGNED */
                    if (weight_wait_cnt < MEM_LATENCY) begin
                    /* verilator lint_on UNSIGNED */
                        weight_wait_cnt <= weight_wait_cnt + 1;
                    end else begin
                        weight_wait_cnt <= 0;
                        if (!weight_half_loaded) begin
                            // First half: load lower 32 bits
                            weight_buffer_lower <= mem_rd_data;
                            mem_addr <= mem_addr + 1;
                            weight_half_loaded <= 1;
                        end else begin
                            // Second half: combine with upper 32 bits and output 64-bit word
                            out_data <= {{(ARRAY_WIDTH*8-64){1'b0}}, mem_rd_data, weight_buffer_lower}; 
                            out_valid <= 1;
                            mem_addr <= mem_addr + 1;
                            weight_half_loaded <= 0;

                            // Load ARRAY_WIDTH rows (one row per cycle after combining two 32-bit reads)
                            if (weight_row_count == ARRAY_WIDTH-1) begin
                                state <= DONE_STATE;
                            end else begin
                                weight_row_count <= weight_row_count + 1;
                            end
                        end
                    end
                end

                PRE_FETCH: begin
                    if (fetch_row_idx < ARRAY_WIDTH) begin
                         if (fifo_count[fetch_row_idx*5 +: 5] < 4 && current_col[fetch_row_idx*16 +: 16] < cfg_img_width) begin
                            // Wrap address if tile boundary reached
                            mem_addr <= tile_boundary ? 16'd0 : next_mem_addr;
                            if (!tile_boundary) begin
                                tile_addr_counter <= tile_addr_counter + 1;
                            end else begin
                                tile_addr_counter <= 0;
                            end
                            mem_req_row_pipe <= fetch_row_idx[2:0];
                            mem_req_valid_pipe <= 1;
                            current_col[fetch_row_idx*16 +: 16] <= current_col[fetch_row_idx*16 +: 16] + 4;
                        end
                        fetch_row_idx <= fetch_row_idx + 1; 
                    end else begin
                        state <= FETCH_INPUTS;
                        fetch_row_idx <= 0;
                    end
                end

                FETCH_INPUTS: begin
                    // Fetch Request
                    if (fifo_count[fetch_row_idx*5 +: 5] < 12 && current_col[fetch_row_idx*16 +: 16] < cfg_img_width) begin
                        // Wrap address if tile boundary reached
                        mem_addr <= tile_boundary ? 16'd0 : next_mem_addr;
                        if (!tile_boundary) begin
                            tile_addr_counter <= tile_addr_counter + 1;
                        end else begin
                            tile_addr_counter <= 0;
                        end
                        mem_req_row_pipe <= fetch_row_idx[2:0];
                        mem_req_valid_pipe <= 1;
                        current_col[fetch_row_idx*16 +: 16] <= current_col[fetch_row_idx*16 +: 16] + 4;
                    end
                    if (fetch_row_idx == ARRAY_WIDTH-1) fetch_row_idx <= 0;
                    else fetch_row_idx <= fetch_row_idx + 1;

                    // Output Logic
                    for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                        if (active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] > 0) begin
                            if (can_fire)
                                active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] <= active_delay_counter[i_seq*CNT_WIDTH +: CNT_WIDTH] - 1;
                        end else begin
                            row_active[i_seq] <= 1;
                        end
                    end

                    if (can_fire) begin
                        out_valid <= 1;
                        for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                            if (row_active[i_seq] && fifo_count[i_seq*5 +: 5] > 0) begin
                                out_data[i_seq*8 +: 8] <= fifo_mem[i_seq][fifo_rd_ptr[i_seq*4 +: 4]];
                                fifo_rd_ptr[i_seq*4 +: 4] <= fifo_rd_ptr[i_seq*4 +: 4] + 1;
                            end else begin
                                out_data[i_seq*8 +: 8] <= 8'd0;
                            end
                        end
                    end
                    // Check for termination condition
                    if (all_rows_done) begin
                        state <= DONE_STATE;
                    end
                end

                DONE_STATE: begin
                    done <= 1;
                    if (!enable) state <= IDLE;
                end

                default: state <= IDLE;
            endcase

            // FIFO Count Update - use appropriate pipeline based on latency
            // Variables for latency-aware signals (moved outside for loop for Verilog compliance)
            begin : fifo_cnt_blk
                reg fifo_write_valid;
                reg [2:0] fifo_write_row;

                if (MEM_LATENCY >= 1) begin
                    fifo_write_valid = mem_req_valid_pipe2;
                    fifo_write_row = mem_req_row_pipe2;
                end else begin
                    fifo_write_valid = mem_req_valid_pipe;
                    fifo_write_row = mem_req_row_pipe;
                end

                for (i_seq=0; i_seq<ARRAY_WIDTH; i_seq=i_seq+1) begin
                    if (fifo_write_valid && {29'd0, fifo_write_row} == i_seq && (state == FETCH_INPUTS || state == PRE_FETCH) && can_fire && row_active[i_seq]) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] + 3; // +4 written, -1 read
                    end else if (fifo_write_valid && {29'd0, fifo_write_row} == i_seq) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] + 4;
                    end else if (state == FETCH_INPUTS && can_fire && row_active[i_seq] && fifo_count[i_seq*5 +: 5] > 0) begin
                        fifo_count[i_seq*5 +: 5] <= fifo_count[i_seq*5 +: 5] - 1;
                    end
                end
            end

            if (mem_req_valid_pipe) begin
                 // Debug removed
            end
            if (state == PRE_FETCH || state == FETCH_INPUTS) begin
                 // Debug removed
            end
        end
    end

    // Termination Check Logic
    reg all_rows_done;
    integer i_term;
    always @(*) begin
        all_rows_done = 1;
        for (i_term=0; i_term<ARRAY_WIDTH; i_term=i_term+1) begin
            if (current_col[i_term*16 +: 16] < cfg_img_width || fifo_count[i_term*5 +: 5] != 0) begin
                all_rows_done = 0;
            end
        end
    end

    // Note: Termination check is now handled inside main always block via all_rows_done
    // The main always block uses 'all_rows_done' to transition from FETCH_INPUTS to DONE_STATE

    // FIFO memory write - use delayed pipeline when MEM_LATENCY >= 1
    generate
        if (MEM_LATENCY >= 1) begin : gen_sram_fifo_write
            always @(posedge clk) begin
                if (mem_req_valid_pipe2) begin
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]]   <= mem_rd_data[7:0];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+1] <= mem_rd_data[15:8];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+2] <= mem_rd_data[23:16];
                    fifo_mem[mem_req_row_pipe2][fifo_wr_ptr[mem_req_row_pipe2*4 +: 4]+3] <= mem_rd_data[31:24];
                end
            end
        end else begin : gen_behav_fifo_write
            always @(posedge clk) begin
                if (mem_req_valid_pipe) begin
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]]   <= mem_rd_data[7:0];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+1] <= mem_rd_data[15:8];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+2] <= mem_rd_data[23:16];
                    fifo_mem[mem_req_row_pipe][fifo_wr_ptr[mem_req_row_pipe*4 +: 4]+3] <= mem_rd_data[31:24];
                end
            end
        end
    endgenerate

endmodule

