module control_unit #(
    parameter ARRAY_WIDTH = 8
)(
    input  wire       clk,
    input  wire       rst_n,
    input  wire       start,
    input  wire [3:0] cfg_kernel_size,
    input  wire [15:0] cfg_img_height,
    input  wire       done_agu,      // Signal from AGU when address generation for a pass is complete
    input  wire       done_drain,    // Signal from Output Handler when draining is complete
    input  wire       loader_done,   // Signal from loader when tile loading complete
    input  wire       swap_done,     // Signal from ping-pong buffer when swap complete
    
    output reg        busy,
    output reg        done,
    
    // Control signals for other modules
    output reg        load_weight,   // To Systolic Array: 1 = Load Mode, 0 = Compute Mode
    output reg        enable_sa,     // To Systolic Array: Enable computation
    output reg        enable_agu,    // To AGU: Enable address generation
    output reg        enable_loader, // To Loader: Enable loading next tile
    output reg        sram_we,       // To SRAM Controller: Write Enable
    output reg        sram_en,       // To SRAM Controller: Chip Enable
    output reg        accumulate_en, // To SRAM/Datapath: 1 = Add to existing partial sum (Pass 2-4), 0 = Overwrite (Pass 1)
    output reg        swap_req,      // To Ping-Pong Buffer: Request bank swap
    output wire [2:0] state_out,     // Debug output for state
    output wire [15:0] start_row_offset // Output row index for AGU
);

    // State Encoding - NVDLA-Style Parallel Pipeline
    localparam IDLE              = 3'b000;
    localparam FILL_FIRST        = 3'b001;  // Fill initial bank
    localparam LOAD_WEIGHTS      = 3'b010;  // Load weights (kept for compatibility)
    localparam COMPUTE_AND_LOAD  = 3'b011;  // Parallel: Compute current + Load next
    localparam DRAIN_LAST        = 3'b100;  // Drain final results
    localparam DONE_STATE        = 3'b101;
    localparam AGU_RESET         = 3'b110;

    reg [2:0] current_state, next_state;

    // Counters
    reg [7:0] drain_counter;       // Counts up to ARRAY_WIDTH (max 255)
    reg [4:0] pass_counter;        // Counts passes (tiles). Max 16 passes for 4x4 array/16x16 kernel.
    reg [15:0] current_output_row; // Tracks which output row we're processing
    reg [4:0] tiles_remaining;     // Tracks remaining tiles to process
    reg loader_started;            // Tracks if loader has been triggered (and cleared its done flag)

    // Internal signals
    wire [4:0] num_tiles;
    wire [4:0] total_passes;
    wire [3:0] kernel_dim;
    wire [15:0] num_output_rows;
    
    // Logic to determine number of passes
    // kernel_size = cfg_kernel_size + 1
    // num_tiles = ceil(kernel_size / ARRAY_WIDTH)
    //           = (kernel_size + ARRAY_WIDTH - 1) / ARRAY_WIDTH
    //           = (cfg_kernel_size + 1 + ARRAY_WIDTH - 1) / ARRAY_WIDTH
    //           = (cfg_kernel_size + ARRAY_WIDTH) / ARRAY_WIDTH
    assign kernel_dim = cfg_kernel_size + 4'd1;
    assign num_output_rows = (cfg_img_height >= {12'd0, kernel_dim}) ? (cfg_img_height - {12'd0, kernel_dim} + 16'd1) : 16'd1;
    assign num_tiles = (cfg_kernel_size + ARRAY_WIDTH) / ARRAY_WIDTH;
    assign total_passes = num_tiles * num_tiles;

    assign state_out = current_state;
    assign start_row_offset = current_output_row;

    // Sequential Logic: State Transition & Counters
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            current_state <= IDLE;
            drain_counter <= 0;
            pass_counter <= 0;
            current_output_row <= 0;
            tiles_remaining <= 0;
            loader_started <= 0;
        end else begin
            current_state <= next_state;

            // Counter Management
            // Drain Counter
            if (current_state == DRAIN_LAST) begin
                if (drain_counter < 100)
                    drain_counter <= drain_counter + 1;
            end else if (current_state == AGU_RESET) begin
                 if (drain_counter < 10)
                    drain_counter <= drain_counter + 1;
            end else begin
                drain_counter <= 0;
            end
            
            // Pass Counter & Tiles Remaining
            if (current_state == IDLE) begin
                pass_counter <= 0;
                current_output_row <= 0;  // Reset output row at start
                loader_started <= 0;  // Reset loader tracking
            end else if (current_state == FILL_FIRST) begin
                // Initialize tiles_remaining here because cfg_kernel_size reg is now valid
                // For now, assume 1 input tile (tiles_remaining = 0 means process 1 tile then done)
                tiles_remaining <= 0;

                // Track loader state: once it clears loader_done, we know it started
                if (!loader_done && !loader_started)
                    loader_started <= 1;
            end else if (current_state == FILL_FIRST && next_state == COMPUTE_AND_LOAD) begin
                tiles_remaining <= tiles_remaining - 1;  // First tile loaded
            end else if (current_state == COMPUTE_AND_LOAD && swap_done) begin
                if (tiles_remaining > 0)
                    tiles_remaining <= tiles_remaining - 1;  // Tile consumed, next loaded
            end else if (current_state == DRAIN_LAST && next_state == LOAD_WEIGHTS) begin
                pass_counter <= pass_counter + 1;
                tiles_remaining <= 0; // Reset for next pass (assume 1 input tile)
            end else if (current_state == DRAIN_LAST && next_state == AGU_RESET) begin
                // Moving to next output row
                drain_counter <= 0; // Force reset for AGU_RESET delay
                current_output_row <= current_output_row + 1;
            end
        end
    end

    // Combinational Logic: Next State Logic - Parallel Pipeline
    always @(*) begin
        next_state = current_state;

        case (current_state)
            IDLE: begin
                if (start)
                    next_state = FILL_FIRST;  // Start by filling first bank
            end

            FILL_FIRST: begin
                // Wait for loader to actually start (done goes low) then complete (done goes high)
                if (loader_started && loader_done)
                    next_state = LOAD_WEIGHTS;  // Request swap and transition (swap completes with swap_req/swap_done handshake)
            end

            LOAD_WEIGHTS: begin
                if (done_agu) 
                    next_state = AGU_RESET;
            end
            
            AGU_RESET: begin
                if (drain_counter >= 2)
                    next_state = COMPUTE_AND_LOAD;  // Enter parallel mode
            end

            COMPUTE_AND_LOAD: begin
                // Parallel state: Compute active bank + Load inactive bank
                if (done_agu && loader_done) begin
                    // Both operations complete - check if more tiles remain
                    if (tiles_remaining > 0) begin
                        next_state = COMPUTE_AND_LOAD;  // Continue loop
                    end else begin
                        next_state = DRAIN_LAST;  // Exit to drain
                    end
                end
            end

            DRAIN_LAST: begin
                if ((done_drain && drain_counter > 60) || drain_counter == 100) begin
                    if (current_output_row < (num_output_rows - 1)) begin
                        // More output rows - restart AGU for next window
                        next_state = AGU_RESET;
                    end else if (pass_counter < total_passes - 1) begin
                        // Current output rows complete, but more tiling passes needed
                        next_state = LOAD_WEIGHTS; // Load next tile
                    end else begin
                        // All output rows and passes complete
                        next_state = DONE_STATE;
                    end
                end
            end

            DONE_STATE: begin
                next_state = IDLE;
            end

            default: next_state = IDLE;
        endcase
    end

    // Output Logic - Parallel Pipeline Control
    always @(*) begin
        // Default values
        busy = 1'b1;
        done = 1'b0;
        load_weight = 1'b0;
        enable_sa = 1'b0;
        enable_agu = 1'b0;
        enable_loader = 1'b0;
        sram_we = 1'b0;
        sram_en = 1'b0;
        accumulate_en = 1'b0;
        swap_req = 1'b0;

        case (current_state)
            IDLE: begin
                busy = 1'b0;
            end

            FILL_FIRST: begin
                enable_loader = 1'b1;  // Load first tile into inactive bank
            end

            LOAD_WEIGHTS: begin
                load_weight = 1'b1; // Enable weight shifting in SA
                enable_sa = 1'b1;   // Clock the SA
                enable_agu = 1'b1; 
                sram_en = 1'b1;     // Read weights from SRAM
                // Request swap at start of LOAD_WEIGHTS so filled bank becomes active
                // This allows AGU to read from the filled bank during COMPUTE
                swap_req = 1'b1;
            end

            AGU_RESET: begin
                enable_agu = 1'b0;  // Reset AGU to IDLE
            end

            COMPUTE_AND_LOAD: begin
                // PARALLEL OPERATIONS
                enable_sa = 1'b1;       // Compute on active bank
                enable_agu = 1'b1;      // AGU reads from active bank
                enable_loader = 1'b1;   // Loader fills inactive bank
                sram_en = 1'b1;         // Enable memory access
                
                // Trigger bank swap when both AGU and loader complete
                if (done_agu && loader_done) begin
                    swap_req = 1'b1;
                end
            end

            DRAIN_LAST: begin
                enable_sa = 1'b1;   // Keep clocking to push data out
                sram_en = 1'b1;     // Enable SRAM for writing results
                sram_we = 1'b1;     // Write results
                
                // Accumulation Logic:
                // Pass 0 (Counter=0): Overwrite (accumulate_en = 0)
                // Pass > 0: Accumulate (accumulate_en = 1)
                if (pass_counter > 0)
                    accumulate_en = 1'b1;
                else
                    accumulate_en = 1'b0;
            end

            DONE_STATE: begin
                busy = 1'b0;
                done = 1'b1;
            end

            default: begin
                busy = 1'b1;
                done = 1'b0;
                load_weight = 1'b0;
                enable_sa = 1'b0;
                enable_agu = 1'b0;
                enable_loader = 1'b0;
                sram_we = 1'b0;
                sram_en = 1'b0;
                accumulate_en = 1'b0;
                swap_req = 1'b0;
            end
        endcase
    end

endmodule

