    reg [15:0] cfg_img_height_reg;
    reg [3:0]  cfg_kernel_size_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cfg_img_width_reg <= cfg_img_width;
            cfg_img_height_reg <= cfg_img_height;
            cfg_kernel_size_reg <= cfg_kernel_size;
        end
    end

    // Internal Signals
    wire        load_weight;
    wire        enable_sa;
    wire        enable_agu;
    wire        sram_we_ctrl;
    wire        sram_en_ctrl;

    wire [2:0]  state_debug;
    wire [15:0] start_row_offset;

