    wire [ARRAY_WIDTH*32-1:0] sa_psum_out; // ARRAY_WIDTH * 32 bits
    wire [ARRAY_WIDTH-1:0]   sa_valid_out; // ARRAY_WIDTH * 1 bit

    // Skew the valid input to match systolic data flow (horizontal skew)
    reg [ARRAY_WIDTH-2:0] valid_skew_reg;
    wire [ARRAY_WIDTH-1:0] sa_valid_in;
    /* verilator lint_on UNUSEDSIGNAL */
    assign sa_valid_in[0] = agu_out_valid;
    assign sa_valid_in[ARRAY_WIDTH-1:1] = valid_skew_reg;

    always @(posedge clk or negedge rst_n) begin
