);

    // -------------------------------------------------------------------------
    // FIFO Implementation
    // -------------------------------------------------------------------------
    reg [31:0] out_fifo [63:0]; // 64-deep FIFO
    reg [5:0]  out_fifo_wr_ptr;
    reg [5:0]  out_fifo_rd_ptr;
    reg [6:0]  out_fifo_count;

    assign fifo_full  = (out_fifo_count == 64);
    assign fifo_empty = (out_fifo_count == 0);

