    /* verilator lint_off UNUSEDSIGNAL */
    reg fifo_read_ack; // Used for debugging/waveform visibility
    /* verilator lint_on UNUSEDSIGNAL */

    // Combinatorial read signal for count update
    wire fifo_read_now = (state == S_IDLE) && enable && !fifo_empty;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            out_fifo_wr_ptr <= 0;
            out_fifo_count <= 0;
        end else begin
