            if (fifo_wr_en && !fifo_full) begin
                out_fifo[out_fifo_wr_ptr] <= fifo_data_in;
                out_fifo_wr_ptr <= out_fifo_wr_ptr + 1;
            end

            // Count Update
            if ((fifo_wr_en && !fifo_full) && fifo_read_now) begin
                // Read and Write simultaneously -> Count stays same
                out_fifo_count <= out_fifo_count;
            end else if (fifo_wr_en && !fifo_full) begin
                // Write only
                out_fifo_count <= out_fifo_count + 1;
