    reg [15:0] col_output_counter;   // Tracks outputs within current row

    wire [15:0] output_width = cfg_img_width - {12'd0, cfg_kernel_size}; 

    // -------------------------------------------------------------------------
    // Read-Modify-Write State Machine
    // -------------------------------------------------------------------------
    localparam S_IDLE       = 2'b00;
    localparam S_READ_WAIT  = 2'b01; // Wait for read data
    localparam S_WRITE      = 2'b10;

