    input  wire        enable,          // From Control Unit (DRAIN state)
    input  wire        accumulate_en,   // From Control Unit
    input  wire        start_pass,      // Reset output index for new pass (connected to load_weight)

    // FIFO Interface (Input from SA)
    input  wire [31:0] fifo_data_in,
    input  wire        fifo_wr_en,
    output wire        fifo_full,      // Optional, for backpressure
    output wire        fifo_empty,     // To signal done

    // Configuration
    input  wire [15:0] cfg_img_width,
    input  wire [3:0]  cfg_kernel_size,

    // Memory Interface
    input  wire [31:0] mem_rd_data,
    output reg  [15:0] mem_addr,
    output reg  [31:0] mem_wr_data,
    output reg         mem_we,
    output reg         mem_en,

    // Status
    output wire        done             // Signals that FIFO is empty and all writes are done
);

    // -------------------------------------------------------------------------
    // FIFO Implementation
    // -------------------------------------------------------------------------
    reg [31:0] out_fifo [63:0]; // 64-deep FIFO
    reg [5:0]  out_fifo_wr_ptr;
    reg [5:0]  out_fifo_rd_ptr;
    reg [6:0]  out_fifo_count;

    assign fifo_full  = (out_fifo_count == 64);
    assign fifo_empty = (out_fifo_count == 0);

    // Internal FIFO Read Ack (controlled by State Machine)
    /* verilator lint_off UNUSEDSIGNAL */
    reg fifo_read_ack; // Used for debugging/waveform visibility
    /* verilator lint_on UNUSEDSIGNAL */

    // Combinatorial read signal for count update
    wire fifo_read_now = (state == S_IDLE) && enable && !fifo_empty;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            out_fifo_wr_ptr <= 0;
            out_fifo_count <= 0;
        end else begin
            // Write Pointer Update
            if (fifo_wr_en && !fifo_full) begin
                out_fifo[out_fifo_wr_ptr] <= fifo_data_in;
                out_fifo_wr_ptr <= out_fifo_wr_ptr + 1;
            end

            // Count Update
            if ((fifo_wr_en && !fifo_full) && fifo_read_now) begin
                // Read and Write simultaneously -> Count stays same
                out_fifo_count <= out_fifo_count;
            end else if (fifo_wr_en && !fifo_full) begin
                // Write only
                out_fifo_count <= out_fifo_count + 1;
            end else if (fifo_read_now) begin
                // Read only
                out_fifo_count <= out_fifo_count - 1;
            end
        end
    end

    // -------------------------------------------------------------------------
    // Address Generation Logic
    // -------------------------------------------------------------------------
    reg [15:0] global_output_index;  // Tracks position across all output rows
    reg [15:0] col_output_counter;   // Tracks outputs within current row

    wire [15:0] output_width = cfg_img_width - {12'd0, cfg_kernel_size}; 

    // -------------------------------------------------------------------------
    // Read-Modify-Write State Machine
    // -------------------------------------------------------------------------
    localparam S_IDLE       = 2'b00;
    localparam S_READ_WAIT  = 2'b01; // Wait for read data
    localparam S_WRITE      = 2'b10;

    reg [1:0] state;

    // Data holding
    reg [31:0] fifo_data_latched;



    // Sequential Logic for Data, State, and Memory Control
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= S_IDLE;
            mem_addr <= 0;
            mem_wr_data <= 0;
            mem_we <= 0;
            mem_en <= 0;
            global_output_index <= 0;
            col_output_counter <= 0;
            out_fifo_rd_ptr <= 0;
            fifo_read_ack <= 0;
            fifo_data_latched <= 0;
        end else begin
            // Reset column counter when not enabled (between rows)
            if (!enable) begin
                col_output_counter <= 0;
            end

            // Reset global index at start of new pass (Weight Loading phase)
            if (start_pass) begin
                global_output_index <= 0;
            end

            // State Machine
            // Default Memory Signals (Pulse generation)
            mem_we <= 0;
            mem_en <= 0;
            fifo_read_ack <= 0;

            case (state)
                S_IDLE: begin
                    if (enable && !fifo_empty) begin
                        // Check if valid output column
                        if (col_output_counter < output_width) begin
                            // Latch data
                            fifo_data_latched <= out_fifo[out_fifo_rd_ptr];

                            // Set Address (Registered, valid next cycle)
                            mem_addr <= 16'h2000 + global_output_index;

                            if (accumulate_en) begin
                                // Start Read (Next Cycle)
                                mem_en <= 1; 
                                mem_we <= 0;
                                state <= S_READ_WAIT;
                            end else begin
                                // Direct Write (Next Cycle)
                                mem_wr_data <= out_fifo[out_fifo_rd_ptr];
                                mem_en <= 1;
                                mem_we <= 1;
                                global_output_index <= global_output_index + 1;
                                state <= S_IDLE;
                            end
                            col_output_counter <= col_output_counter + 1;

                            // Advance FIFO
                            out_fifo_rd_ptr <= out_fifo_rd_ptr + 1;
                            fifo_read_ack <= 1;
                        end else begin
                            // Discard garbage data
                            out_fifo_rd_ptr <= out_fifo_rd_ptr + 1;
                            fifo_read_ack <= 1;
                            state <= S_IDLE;
                        end
                    end
                end

                S_READ_WAIT: begin
                    // We are in Cycle 1 (Read started).
                    // Data will be valid in Cycle 2.
                    // Prepare for Write in Cycle 2.
                    // We need to keep mem_addr stable? Yes, it's registered.

                    // Actually, for RMW, we read at Addr, then Write to SAME Addr.
                    // So we don't change mem_addr.
                    state <= S_WRITE;
                end

                S_WRITE: begin
                    // Cycle 2. Data from RAM (mem_rd_data) is valid.
                    // Perform Add and Write.
                    mem_wr_data <= fifo_data_latched + mem_rd_data;
                    mem_en <= 1;
                    mem_we <= 1;

                    global_output_index <= global_output_index + 1;
                    state <= S_IDLE;
                end

                default: begin
                    state <= S_IDLE;
                end
            endcase



        end
    end

    // Done signal: When FIFO is empty AND State is IDLE (no pending RMW)
    assign done = fifo_empty && (state == S_IDLE);

endmodule

