import os

def convert_csv_to_hex(input_file, output_file, is_kernel=False):
    with open(input_file, 'r') as f:
        lines = f.readlines()

    hex_values = []
    for line in lines:
        if not line.strip():
            continue
        # Split by comma and strip whitespace
        vals = [v.strip() for v in line.split(',')]
        for v in vals:
            if v:
                try:
                    # Convert to integer then to 2-digit hex
                    int_val = int(v)
                    # Handle negative numbers if any (assuming 8-bit 2's complement if needed, but data seems positive)
                    if int_val < 0:
                        int_val = (1 << 8) + int_val
                    hex_val = f"{int_val:02x}"
                    hex_values.append(hex_val)
                except ValueError:
                    pass

    # For kernel, we might need special handling if the testbench expects a specific layout,
    # but for now we'll just dump the values linearly. 
