        #10;
        if (state_out !== IDLE) $error("Failed to return to IDLE");
        
        $display("Test Case 1 Passed");

        // Test Case 2: Large Kernel (16x16) - 4 Passes
        #20;
        $display("Starting Test Case 2: Large Kernel (16x16)");
        cfg_kernel_size = 4'd15; // Large kernel (16x16, 0-indexed: 15)
        start = 1;
        #10;
        start = 0;

        // Loop through 4 passes
        repeat (4) begin
            // LOAD
            wait(state_out == LOAD_WEIGHTS);
            $display("Entered LOAD_WEIGHTS");
            #80; // Wait for load time
            done_agu = 1; // Signal AGU done
            #10;
            done_agu = 0;

            // COMPUTE
            wait(state_out == COMPUTE);
            $display("Entered COMPUTE");
            #50; // Some compute time
            done_agu = 1;
            #10;
            done_agu = 0;

            // DRAIN
            wait(state_out == DRAIN);
            $display("Entered DRAIN");
