`timescale 1ns / 1ps

module tb_control_unit_4x4;

    // Parameters
    parameter ARRAY_WIDTH = 4;

    // Inputs
    reg clk;
    reg rst_n;
    reg start;
    reg [3:0] cfg_kernel_size;
    reg done_agu;
    reg done_drain;

    // Outputs
    wire busy;
    wire done;
    wire load_weight;
    wire enable_sa;
    wire enable_agu;
    wire sram_we;
    wire sram_en;
    wire accumulate_en;
    wire [2:0] state_out;

    // State Encoding (must match RTL)
    localparam IDLE         = 3'b000;
    localparam LOAD_WEIGHTS = 3'b001;
    localparam COMPUTE      = 3'b010;
    localparam DRAIN        = 3'b011;
    localparam DONE_STATE   = 3'b100;
    localparam AGU_RESET    = 3'b101;

    // Instantiate the Unit Under Test (UUT)
    control_unit #(
        .ARRAY_WIDTH(ARRAY_WIDTH)
    ) uut (
        .clk(clk), 
        .rst_n(rst_n), 
        .start(start), 
        .cfg_kernel_size(cfg_kernel_size), 
        .done_agu(done_agu), 
        .done_drain(done_drain), 
        .busy(busy), 
        .done(done), 
        .load_weight(load_weight), 
        .enable_sa(enable_sa), 
        .enable_agu(enable_agu), 
        .sram_we(sram_we), 
        .sram_en(sram_en), 
        .accumulate_en(accumulate_en),
        .state_out(state_out)
    );

    // Clock generation
    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    integer pass_count;
    integer tests_passed;
    integer tests_total;

    // Task to run a single test case
    task run_test;
        input [3:0] k_size_cfg;
        input [4:0] expected_passes;
        integer k_size_actual;
        reg in_drain;
        begin
            k_size_actual = k_size_cfg + 1;
            in_drain = 0;
            $display("\n----------------------------------------------------------------");
            $display("Testing Kernel Size: %0d (cfg=%0d), Expected Passes: %0d", k_size_actual, k_size_cfg, expected_passes);

            // Reset
            rst_n = 0;
            start = 0;
            cfg_kernel_size = k_size_cfg;
            done_agu = 0;
            done_drain = 0;
            pass_count = 0;

            #20;
            rst_n = 1;
            #20;

            // Start
            start = 1;
            #10;
            start = 0;

            // Wait for completion
            while (!done) begin
                @(posedge clk);

                // Simulate AGU and Drain signals based on state
                if (state_out == LOAD_WEIGHTS) begin
                    in_drain = 0;
                    // Only print for first few passes to reduce clutter
                    // $display("  Entered LOAD_WEIGHTS (Pass %0d)", pass_count);
                    #20; 
                    done_agu = 1;
                    #10;
                    done_agu = 0;
                end
                else if (state_out == AGU_RESET) begin
                    in_drain = 0;
                    #10;
                end
                else if (state_out == COMPUTE) begin
                    in_drain = 0;
                    #20; 
                    done_agu = 1;
                    #10;
                    done_agu = 0;
                end
                else if (state_out == DRAIN) begin
                    if (!in_drain) begin
                         pass_count = pass_count + 1;
                         in_drain = 1;
                    end
                    #20; 
                    done_drain = 1;
                    #10;
                    done_drain = 0;
                end
                else begin
                    in_drain = 0;
                end
            end

            tests_total = tests_total + 1;
            if (pass_count == expected_passes) begin
                $display("PASS: Executed %0d passes.", pass_count);
                tests_passed = tests_passed + 1;
            end else begin
                $display("FAIL: Executed %0d passes (Expected %0d).", pass_count, expected_passes);
            end
            #50;
        end
    endtask

    initial begin
        // Initialize
        clk = 0;
        tests_passed = 0;
        tests_total = 0;

        // ---------------------------------------------------------
        // Test Cases
        // Formula: passes = ceil(k_size / 4)^2
        // ---------------------------------------------------------

        // 1. Kernel Size 4 (cfg=3) -> ceil(1) = 1 -> 1 pass
        run_test(4'd3, 5'd1);

        // 2. Kernel Size 5 (cfg=4) -> ceil(1.25) = 2 -> 4 passes
        run_test(4'd4, 5'd4);

        // 3. Kernel Size 7 (cfg=6) -> ceil(1.75) = 2 -> 4 passes
        run_test(4'd6, 5'd4);

        // 4. Kernel Size 8 (cfg=7) -> ceil(2) = 2 -> 4 passes
        run_test(4'd7, 5'd4);

        // 5. Kernel Size 9 (cfg=8) -> ceil(2.25) = 3 -> 9 passes
        run_test(4'd8, 5'd9);

        // 6. Kernel Size 11 (cfg=11) -> ceil(2.75) = 3 -> 9 passes
        run_test(4'd11, 5'd9);

        // 7. Kernel Size 15 (cfg=14) -> ceil(3.75) = 4 -> 16 passes
        run_test(4'd14, 5'd16);

        // 8. Kernel Size 16 (cfg=15) -> ceil(4) = 4 -> 16 passes
        run_test(4'd15, 5'd16);

        $display("\n----------------------------------------------------------------");
        $display("Summary: %0d/%0d Tests Passed", tests_passed, tests_total);
        if (tests_passed == tests_total) $display("ALL TESTS PASSED");
        else $display("SOME TESTS FAILED");

        $finish;
    end

endmodule

