`timescale 1ns / 1ps

module tb_5x5_ones;

    reg clk;
    reg rst_n;
    reg start;
    wire done;
    wire busy;

    // Configuration
    reg [15:0] cfg_img_width;
    reg [15:0] cfg_img_height;
    reg [3:0]  cfg_kernel_size;

    // Handshake Monitor removed

    // Memory Interface Signals
    // DUT Outputs
    wire [15:0] dut_mem_addr;
    wire [31:0] dut_mem_wr_data;
    wire        dut_mem_we;
    wire        dut_mem_en;

    // Behavioral Memory
    reg [31:0] memory [0:65535]; // 64K words "Infinite" for this test

    // Asynchronous Read
    wire [31:0] dut_mem_rd_data;
    assign dut_mem_rd_data = memory[dut_mem_addr];

    // Instantiation
    convolution_accel u_dut (
        .clk             (clk),
        .rst_n           (rst_n),
        .start           (start),
        .done            (done),
        .busy            (busy),
        .cfg_img_width   (cfg_img_width),
        .cfg_img_height  (cfg_img_height),
        .cfg_kernel_size (cfg_kernel_size),
        .mem_rd_data     (dut_mem_rd_data), // Connected to new asynchronous read wire
        .mem_addr        (dut_mem_addr),
        .mem_wr_data     (dut_mem_wr_data),
        .mem_we          (dut_mem_we),
        .mem_en          (dut_mem_en)
    );

    // Behavioral Memory Logic
    always @(posedge clk) begin
        if (dut_mem_en && dut_mem_we) begin // Simplified condition for write only
            memory[dut_mem_addr] <= dut_mem_wr_data;
        end
        // Removed the else branch for read as it's now asynchronous
    end

    // Clock Generation
    initial clk = 0;
    always #25 clk = ~clk; // 50ns period (20MHz)

    integer i, j;

    initial begin
        $dumpfile("tb_5x5_ones.vcd");
        $dumpvars(0, tb_5x5_ones);
        $display("Running NEW tb_custom_5x5.v with CORRECT weights");

        // Initialize
        rst_n = 0;
        start = 0;
        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2; // 3x3 Kernel

        // Initialize Memory
        for (i = 0; i < 65536; i = i + 1) begin
            memory[i] = 32'd0;
        end

        // Weights (3x3 Kernel, all 1s)
        // Address 0x0000 start.
        // Layout: Row 0, Row 1, Row 2...
        // But AGU loads into SA rows.
        // We need to match the AGU's loading sequence.
        // AGU loads:
        // Row 0 of SA gets first weight word?
        // Let's check AGU FETCH_WEIGHTS.
        // It reads mem_addr 0, 1, 2...
        // And outputs {mem_rd_data, weight_buffer_lower}.
        // It outputs 64 bits (8 weights of 8 bits).
        // So each memory read (32 bits) provides 4 weights.
        // We need 8 weights per row?
        // SA width is 8.
        // So we need 64 bits per row.
        // AGU reads 2 x 32-bit words to form 64-bit output.
        // So 2 memory addresses per SA row.

        // Kernel is 3x3.
        // We want:
        // SA Row 0: 1, 1, 1, 0, 0, 0, 0, 0
        // SA Row 1: 1, 1, 1, 0, 0, 0, 0, 0
        // SA Row 2: 1, 1, 1, 0, 0, 0, 0, 0
        // SA Row 3-7: 0...

        // Address Mapping:
        // SA Row 0: Addr 0, 1
        // SA Row 1: Addr 2, 3
        // ...

        // Initialize Memory (Weights)
        // AGU loads 8 rows (Row 7 down to Row 0).
        // Each row takes 2 words (64 bits).

        // Clear Rows 7-3 (Addr 0-9)
        for (i=0; i<10; i=i+1) memory[i] = 0;

        // Row 2 (Bottom): 240, 39, 121 -> 0x007927F0
        memory[16'h000A] = 32'h007927F0;
        memory[16'h000B] = 32'h00000000;

        // Row 1 (Middle): 152, 102, 214 -> 0x00D66698
        memory[16'h000C] = 32'h00D66698;
        memory[16'h000D] = 32'h00000000;

        // Row 0 (Top): 20, 44, 203 -> 0x00CB2C14
        memory[16'h000E] = 32'h00CB2C14;
        memory[16'h000F] = 32'h00000000;

        // Input Image (5x5) stored in word-aligned row-major layout
        // Each row needs ceil(width/4) = ceil(5/4) = 2 words
        // Rows are spaced to match AGU's addressing expectations
        // Row 0: 102, 220, 225, 95, 179
        // Row 1: 61, 234, 203, 92, 3
        // Row 2: 98, 243, 14, 149, 245
        // Row 3: 46, 106, 244, 99, 187
        // Row 4: 71, 212, 153, 199, 188

        // Clear image area first
        for (i=16'h1000; i<16'h1030; i=i+1) memory[i] = 0;

        // Row 0: offset 0 (word-aligned at 0x1000)
        memory[16'h1000] = 32'h5FE1DC66; // pixels 0-3: 102, 220, 225, 95
        memory[16'h1001] = 32'h000000B3; // pixel 4: 179

        // Row 1: offset 5 words -> AGU will read from 0x1005, 0x1006
        memory[16'h1005] = 32'h5CCBEA3D; // pixels 0-3: 61, 234, 203, 92
        memory[16'h1006] = 32'h00000003; // pixel 4: 3

        // Row 2: offset 10 words -> AGU will read from 0x100A, 0x100B
        memory[16'h100A] = 32'h950EF362; // pixels 0-3: 98, 243, 14, 149
        memory[16'h100B] = 32'h000000F5; // pixel 4: 245

        // Row 3: offset 15 words -> AGU will read from 0x100F, 0x1010
        memory[16'h100F] = 32'h63F46A2E; // pixels 0-3: 46, 106, 244, 99
        memory[16'h1010] = 32'h000000BB; // pixel 4: 187

        // Row 4: offset 20 words -> AGU will read from 0x1014, 0x1015
        memory[16'h1014] = 32'hC799D447; // pixels 0-3: 71, 212, 153, 199
        memory[16'h1015] = 32'h000000BC; // pixel 4: 188

        // Reset Pulse
        #200;
        rst_n = 1; // Release reset

        // ---------------------------------------------------------------------
        // Start Convolution
        // ---------------------------------------------------------------------
        $display("Starting Convolution...");
        @(posedge clk);
        start = 1;
        @(posedge clk);
        @(posedge clk);
        start = 0;

        // Wait for Done
        wait(done);
        $display("Convolution Done!");

        // ---------------------------------------------------------------------
        // 1. Initialize Memory (Weights & Inputs)
        // ---------------------------------------------------------------------


        // ---------------------------------------------------------------------
        // Verify Results
        // ---------------------------------------------------------------------
        #50;
        $display("Verifying Results (3x3 Valid Convolution Output)...");

        // Expected Output (3x3) stored linearly:
        // 168668, 186442, 124715
        // 140101, 149473, 163521
        // 129335, 178835, 211004

        // Hardware stores 3x3 output linearly starting at 0x2000
        // Row 0: 0x2000, 0x2001, 0x2002
        // Row 1: 0x2003, 0x2004, 0x2005
        // Row 2: 0x2006, 0x2007, 0x2008

        // Row 0
        check_result(16'h2000, 32'd168668);
        check_result(16'h2001, 32'd186442);
        check_result(16'h2002, 32'd124715);

        // Row 1
        check_result(16'h2003, 32'd140101);
        check_result(16'h2004, 32'd149473);
        check_result(16'h2005, 32'd163521);

        // Row 2
        check_result(16'h2006, 32'd129335);
        check_result(16'h2007, 32'd178835);
        check_result(16'h2008, 32'd211004);

        $display("Verification Complete.");
        $finish;
    end

    task check_result;
        input [15:0] addr;
        input [31:0] expected;
        reg [31:0] actual;
        begin
            actual = memory[addr];
            if (actual !== expected) begin
                $display("ERROR: Result at Addr %h is %d (Expected %d)", addr, actual, expected);
            end else begin
                $display("PASS: Result at Addr %h is %d", addr, actual);
            end
        end
    endtask

    // Monitor
    always begin
        #10000; // Check every 10us
        $display("Time %t: Busy=%b, Done=%b, State=%b, AGU_State=%b, AGU_Done=%b, Drain_Done=%b", 
            $time, busy, done, u_dut.u_control_unit.current_state, u_dut.u_agu.state, u_dut.done_agu, u_dut.done_drain);
    end

    // Debug Data Flow
    always @(posedge clk) begin
        if (u_dut.agu_out_valid) begin
            $display("Time %t: [AGU] Valid Data: %h (Addr: %h)", $time, u_dut.agu_out_data, u_dut.agu_mem_addr);
        end
        if (u_dut.load_weight || u_dut.enable_sa) begin
             $display("Time %t: [CTRL] Load W: %b, En SA: %b, SA W In: %h", $time, u_dut.load_weight, u_dut.enable_sa, u_dut.sa_weight_in);
        end
        if (u_dut.sa_valid_out[0]) begin // Check first column valid
             //$display("Time %t: [SA] Col 0 Valid", $time);
        end
        if (u_dut.final_valid) begin
            $display("Time %t: [SA] Final Valid Output: %d", $time, u_dut.sa_final_output);
        end
        // Monitor SA Partial Sum Outputs (Bottom Row)
        if (u_dut.enable_sa && !u_dut.load_weight) begin
            if (u_dut.sa_psum_out !== 0)
                $display("Time %t: [SA] PSUM Out: %h", $time, u_dut.sa_psum_out);
        end
        if (u_dut.u_output_handler.fifo_wr_en) begin
            $display("Time %t: [FIFO] Write: %d (Count: %d)", $time, u_dut.u_output_handler.fifo_data_in, u_dut.u_output_handler.out_fifo_count);
        end
        if (u_dut.mem_en && !u_dut.mem_we) begin
             $display("Time %t: [MEM] Read Addr: %h Data: %h", $time, u_dut.mem_addr, dut_mem_rd_data);
        end
        if (u_dut.mem_en && u_dut.mem_we) begin
             $display("Time %t: [MEM] WRITE Addr: %h Data: %h", $time, u_dut.mem_addr, u_dut.mem_wr_data);
        end
    end

    // Monitor removed

    // Timeout
    initial begin
        #20000000; // 20ms
        $display("Error: Simulation Timeout!");
        $finish;
    end

endmodule

