`timescale 1ns / 1ps

// Full System Testbench using Behavioral Memory
// Tests 3x3 kernel of all 1s with 5x5 input of all 1s
// Expected output: 3x3 matrix of all 9s

module tb_full_system;

    reg clk;
    reg rst_n;
    reg start;
    wire done;
    wire busy;

    // Configuration
    reg [15:0] cfg_img_width;
    reg [15:0] cfg_img_height;
    reg [3:0]  cfg_kernel_size;

    // Memory Interface
    wire [15:0] mem_addr;
    wire [31:0] mem_wr_data;
    wire        mem_we;
    wire        mem_en;

    // Behavioral Memory
    reg [31:0] memory [0:65535]; // 64K words

    // Asynchronous Read (same as tb_custom_5x5.v)
    wire [31:0] mem_rd_data;
    assign mem_rd_data = memory[mem_addr];

    // Instantiation
    convolution_accel u_dut (
        .clk             (clk),
        .rst_n           (rst_n),
        .start           (start),
        .done            (done),
        .busy            (busy),
        .cfg_img_width   (cfg_img_width),
        .cfg_img_height  (cfg_img_height),
        .cfg_kernel_size (cfg_kernel_size),
        .mem_rd_data     (mem_rd_data),
        .mem_addr        (mem_addr),
        .mem_wr_data     (mem_wr_data),
        .mem_we          (mem_we),
        .mem_en          (mem_en)
    );

    // Behavioral Memory Write Logic
    always @(posedge clk) begin
        if (mem_en && mem_we) begin
            memory[mem_addr] <= mem_wr_data;
            $display("Time %t: Memory Write Addr=%h Data=%h", $time, mem_addr, mem_wr_data);
        end
    end

    // Clock Generation
    initial clk = 0;
    always #25 clk = ~clk; // 50ns period (20MHz)

    integer i;

    initial begin
        $dumpfile("tb_full_system.vcd");
        $dumpvars(0, tb_full_system);
        $display("=== Full System Test (Behavioral Memory) ===");

        // Initialize
        rst_n = 0;
        start = 0;
        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2; // 3x3 Kernel (size - 1)

        // Initialize all memory to 0
        for (i = 0; i < 65536; i = i + 1) begin
            memory[i] = 32'd0;
        end

        // Reset Pulse
        #200;
        rst_n = 1;

        // ---------------------------------------------------------------------
        // Initialize Memory
        // ---------------------------------------------------------------------
        $display("Initializing Weights...");

        // Weights for 3x3 Kernel (all 1s)
        // 
        // IMPORTANT: Weights are stored in REVERSE order because of how the 
        // systolic array loads weights. During weight loading, weights shift DOWN
        // through the array. So:
        //   - First weight loaded (0x0000) ends up in SA Row 7 (bottom)
        //   - Last weight loaded (0x000E/F) ends up in SA Row 0 (top)
        //
        // For a 3x3 kernel processed by the top-left 3x3 of the 8x8 array:
        //   - Kernel Row 0 (top) → needs to be in SA Row 0 → stored at 0x000E/F (last loaded)
        //   - Kernel Row 1 → needs to be in SA Row 1 → stored at 0x000C/D
        //   - Kernel Row 2 (bottom) → needs to be in SA Row 2 → stored at 0x000A/B
        //
        // Addresses 0x0000-0x0009 load into SA Rows 7-3 (unused for 3x3 kernel, set to 0)

        // Clear all weight area first
        for (i = 0; i < 16; i = i + 1) begin
            memory[i] = 32'h00000000;
        end

        // Row 0 (Top): 1, 1, 1 -> 0x010101 (loaded last, ends up in SA Row 0)
        memory[16'h000E] = 32'h00010101; 
        memory[16'h000F] = 32'h00000000;

        // Row 1 (Middle): 1, 1, 1 -> 0x010101 (ends up in SA Row 1)
        memory[16'h000C] = 32'h00010101;
        memory[16'h000D] = 32'h00000000;

        // Row 2 (Bottom): 1, 1, 1 -> 0x010101 (ends up in SA Row 2)
        memory[16'h000A] = 32'h00010101;
        memory[16'h000B] = 32'h00000000;

        $display("Initializing Input Image...");
        // Input Image (5x5) at addresses starting at 0x1000
        // Each row needs ceil(5/4) = 2 words
        // Row spacing: cfg_img_width = 5 words apart

        // Row 0: offset 0 (at 0x1000)
        memory[16'h1000] = 32'h01010101; // pixels 0-3
        memory[16'h1001] = 32'h00000001; // pixel 4

        // Row 1: offset 5 (at 0x1005)
        memory[16'h1005] = 32'h01010101;
        memory[16'h1006] = 32'h00000001;

        // Row 2: offset 10 (at 0x100A)
        memory[16'h100A] = 32'h01010101;
        memory[16'h100B] = 32'h00000001;

        // Row 3: offset 15 (at 0x100F)
        memory[16'h100F] = 32'h01010101;
        memory[16'h1010] = 32'h00000001;

        // Row 4: offset 20 (at 0x1014)
        memory[16'h1014] = 32'h01010101;
        memory[16'h1015] = 32'h00000001;

        $display("Starting Convolution...");

        // Start Convolution
        @(posedge clk);
        start = 1;
        @(posedge clk);
        start = 0;

        // Wait for Done
        wait(done);
        $display("Convolution Done!");

        // Verify Results
        // For 5x5 input with 3x3 kernel, output is 3x3 = 9 values
        // All outputs should be 9 (sum of 9 ones)
        // Output addresses: 0x2000 - 0x2008

        $display("Verifying Results...");
        for (i = 0; i < 9; i = i + 1) begin
            if (memory[16'h2000 + i] !== 32'd9) begin
                $display("Error: Result at 0x%h is %d (Expected 9)", 16'h2000 + i, memory[16'h2000 + i]);
            end else begin
                $display("PASS: Result at 0x%h is %d", 16'h2000 + i, memory[16'h2000 + i]);
            end
        end

        $display("Verification Complete.");

        $finish;
    end

    // Monitor (periodic status)
    always @(posedge clk) begin
        if ($time % 1000000 == 0 && $time > 0) begin
            $display("Time %t: Busy=%b, Done=%b, Mem_Addr=%h", $time, busy, done, mem_addr);
        end
    end

endmodule

