        // Output addresses: 0x2000 - 0x2008

        $display("Verifying Results...");
        for (i = 0; i < 9; i = i + 1) begin
            if (memory[16'h2000 + i] !== 32'd9) begin
                $display("Error: Result at 0x%h is %d (Expected 9)", 16'h2000 + i, memory[16'h2000 + i]);
            end else begin
                $display("PASS: Result at 0x%h is %d", 16'h2000 + i, memory[16'h2000 + i]);
            end
        end

        $display("Verification Complete.");

        $finish;
    end

    // Monitor (periodic status)
    always @(posedge clk) begin
        if ($time % 1000000 == 0 && $time > 0) begin
            $display("Time %t: Busy=%b, Done=%b, IfmapAddr=%h, OfmapAddr=%h", $time, busy, done, ifmap_rd_addr, ofmap_wr_addr);
        end
    end

endmodule

