        // =====================================================================
        // TEST 3: 3x3 Identity, 5x5 Unique Values
        // =====================================================================
        reset_dut();
        clear_memory();

        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2;

        // Identity kernel: center = 1
        memory[16'h000E] = 32'h00000000;
        memory[16'h000C] = 32'h00000100;
        memory[16'h000A] = 32'h00000000;

