        memory[16'h1000] = 32'h0E_0D_0C_0B; memory[16'h1001] = 32'h0000000F;
        memory[16'h1005] = 32'h18_17_16_15; memory[16'h1006] = 32'h00000019;
        memory[16'h100A] = 32'h22_21_20_1F; memory[16'h100B] = 32'h00000023;
        memory[16'h100F] = 32'h2C_2B_2A_29; memory[16'h1010] = 32'h0000002D;
        memory[16'h1014] = 32'h36_35_34_33; memory[16'h1015] = 32'h00000037;

        num_expected = 9;
        expected_outputs[0] = 22; expected_outputs[1] = 23; expected_outputs[2] = 24;
        expected_outputs[3] = 32; expected_outputs[4] = 33; expected_outputs[5] = 34;
        expected_outputs[6] = 42; expected_outputs[7] = 43; expected_outputs[8] = 44;

        run_and_verify("3x3 Identity, 5x5 Unique", num_expected);

        // =====================================================================
        // TEST 4: 3x3 Diagonal, 5x5 Ones (expect 3s)
        // =====================================================================
        reset_dut();
        clear_memory();

        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2;

        memory[16'h000E] = 32'h00000001; // [1,0,0]
        memory[16'h000C] = 32'h00000100; // [0,1,0]
        memory[16'h000A] = 32'h00010000; // [0,0,1]

        memory[16'h1000] = 32'h01010101; memory[16'h1001] = 32'h00000001;
        memory[16'h1005] = 32'h01010101; memory[16'h1006] = 32'h00000001;
        memory[16'h100A] = 32'h01010101; memory[16'h100B] = 32'h00000001;
        memory[16'h100F] = 32'h01010101; memory[16'h1010] = 32'h00000001;
        memory[16'h1014] = 32'h01010101; memory[16'h1015] = 32'h00000001;

        num_expected = 9;
        for (i = 0; i < 9; i = i + 1) expected_outputs[i] = 32'd3;

        run_and_verify("3x3 Diagonal, 5x5 Ones", num_expected);

        // =====================================================================
        // TEST 5: tb_custom_5x5 equivalent
        // =====================================================================
        reset_dut();
        clear_memory();

        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2;

        // Kernel from tb_custom_5x5: [20,44,203], [152,102,214], [240,39,121]
        memory[16'h000E] = 32'h00CB2C14; // Row 0: 20, 44, 203
        memory[16'h000C] = 32'h00D66698; // Row 1: 152, 102, 214
        memory[16'h000A] = 32'h007927F0; // Row 2: 240, 39, 121

        // Image from tb_custom_5x5
        memory[16'h1000] = 32'h5FE1DC66; memory[16'h1001] = 32'h000000B3;
        memory[16'h1005] = 32'h5CCBEA3D; memory[16'h1006] = 32'h00000003;
        memory[16'h100A] = 32'h950EF362; memory[16'h100B] = 32'h000000F5;
        memory[16'h100F] = 32'h63F46A2E; memory[16'h1010] = 32'h000000BB;
        memory[16'h1014] = 32'hC799D447; memory[16'h1015] = 32'h000000BC;

        num_expected = 9;
        expected_outputs[0] = 168668; expected_outputs[1] = 186442; expected_outputs[2] = 124715;
        expected_outputs[3] = 140101; expected_outputs[4] = 149473; expected_outputs[5] = 163521;
        expected_outputs[6] = 129335; expected_outputs[7] = 178835; expected_outputs[8] = 211004;

        run_and_verify("tb_custom_5x5 equivalent", num_expected);

        // =====================================================================
        // SUMMARY
        // =====================================================================
        $display("\n################################################################");
        $display("#                    TEST SUMMARY                             #");
        $display("################################################################");
        $display("  Total Tests:  %0d", total_tests);
        $display("  Passed:       %0d", passed_tests);
        $display("  Failed:       %0d", failed_tests);
        $display("################################################################");

        if (failed_tests == 0) begin
            $display("\n  >>> ALL TESTS PASSED! <<<\n");
        end else begin
            $display("\n  >>> SOME TESTS FAILED <<<\n");
        end

        $finish;
    end

endmodule

