`timescale 1ns / 1ps

// Multi-Test Testbench using SKY130 SRAM
// Uses the actual SRAM model with backdoor initialization

module tb_sram_multi_test;

    reg clk;
    reg rst_n;
    reg start;
    wire done;
    wire busy;

    reg [15:0] cfg_img_width;
    reg [15:0] cfg_img_height;
    reg [3:0]  cfg_kernel_size;

    // Ping-Pong Compatibility Signals
    wire        enable_loader;
    wire        swap_req;
    reg         loader_done;
    reg         swap_done;
    reg [3:0]   loader_delay_cnt;
    reg         swap_req_d;

    // Memory Interface - Separated Channels
    // Input Channel (Read)
    wire [15:0] ifmap_rd_addr;
    wire        ifmap_rd_en;
    wire [31:0] ifmap_rd_data;

    // Output Channel (Write)
    wire [15:0] ofmap_wr_addr;
    wire [31:0] ofmap_wr_data;
    wire        ofmap_we;
    wire        ofmap_en;

    // DUT
    convolution_accel #(
        .ARRAY_WIDTH(8),
        .MEM_LATENCY(2)  // SKY130 SRAM has 2-cycle read latency
    ) u_dut (
        .clk             (clk),
        .rst_n           (rst_n),
        .start           (start),
        .done            (done),
        .busy            (busy),
        .cfg_img_width   (cfg_img_width),
        .cfg_img_height  (cfg_img_height),
        .cfg_kernel_size (cfg_kernel_size),
        // Input Channel
        .ifmap_rd_data   (ifmap_rd_data),
        .ifmap_rd_addr   (ifmap_rd_addr),
        .ifmap_rd_en     (ifmap_rd_en),
        // Output Channel
        .ofmap_wr_data   (ofmap_wr_data),
        .ofmap_wr_addr   (ofmap_wr_addr),
        .ofmap_we        (ofmap_we),
        .ofmap_en        (ofmap_en),
        // Ping-Pong Control (compatibility mode)
        .loader_done     (loader_done),
        .swap_done       (swap_done),
        .enable_loader   (enable_loader),
        .swap_req        (swap_req)
    );

    // SKY130 SRAM via wrapper - connected to both channels
    // Route based on address space or create dual SRAM instances
    // For simplicity, use single SRAM with muxed access
    wire        sram_en = ifmap_rd_en | ofmap_en;
    wire        sram_we = ofmap_we;
    wire [15:0] sram_addr = ofmap_en ? ofmap_wr_addr : ifmap_rd_addr;
    wire [31:0] sram_wr_data = ofmap_wr_data;
    wire [31:0] sram_rd_data;
    assign ifmap_rd_data = sram_rd_data;

    sram_ctrl_wrapper u_sram (
        .clk         (clk),
        .rst_n       (rst_n),
        .mem_en      (sram_en),
        .mem_we      (sram_we),
        .mem_addr    (sram_addr),
        .mem_wr_data (sram_wr_data),
        .mem_rd_data (sram_rd_data)
    );

    // Ping-Pong Compatibility Logic
    // Simulate loader completion: assert loader_done after enable_loader goes high
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            loader_done <= 1'b0;
            loader_delay_cnt <= 0;
        end else begin
            if (enable_loader && loader_delay_cnt < 4'd10) begin
                loader_delay_cnt <= loader_delay_cnt + 1;
                loader_done <= 1'b0;
            end else if (loader_delay_cnt == 4'd10) begin
                loader_done <= 1'b1;
                loader_delay_cnt <= 0;
            end else if (!enable_loader) begin
                loader_done <= 1'b0;
                loader_delay_cnt <= 0;
            end
        end
    end

    // Simulate swap completion: pulse swap_done when swap_req goes high
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            swap_done <= 1'b0;
            swap_req_d <= 1'b0;
        end else begin
            swap_req_d <= swap_req;
            // Detect rising edge of swap_req
            if (swap_req && !swap_req_d) begin
                swap_done <= 1'b1;
            end else begin
                swap_done <= 1'b0;
            end
        end
    end

    // Clock
    initial clk = 0;
    always #25 clk = ~clk;

    // Counters
    integer total_tests = 0;
    integer passed_tests = 0;
    integer failed_tests = 0;
    integer i, j;

    // Expected values
    reg [31:0] expected_outputs [0:255];
    integer num_expected;

    // =========================================================================
    // Backdoor write task - handles SRAM's interleaved addressing
    // SRAM uses: LSB 3 bits = serial index (0-7), MSB 9 bits = offset
    // =========================================================================
    task write_sram_backdoor;
        input [15:0] logical_addr;
        input [31:0] data;
        reg [11:0] mapped_addr;
        integer serial_idx;
        integer offset;
        begin
            // Apply the same mapping as sram_ctrl_wrapper
            if (logical_addr[15:12] == 4'h0) begin
                mapped_addr = logical_addr[11:0];
            end else if (logical_addr[15:12] == 4'h1) begin
                mapped_addr = 12'd100 + logical_addr[13:2];
            end else if (logical_addr[15:12] == 4'h2) begin
                mapped_addr = 12'd300 + logical_addr[11:0];
            end else begin
                mapped_addr = logical_addr[11:0];
            end

            // Interleaved addressing: LSB 3 bits = serial, MSB 9 bits = offset
            serial_idx = mapped_addr[2:0];
            offset = mapped_addr[11:3];

            case (serial_idx)
                0: u_sram.sram_inst.SERIAL_MEMORY[0].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                1: u_sram.sram_inst.SERIAL_MEMORY[1].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                2: u_sram.sram_inst.SERIAL_MEMORY[2].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                3: u_sram.sram_inst.SERIAL_MEMORY[3].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                4: u_sram.sram_inst.SERIAL_MEMORY[4].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                5: u_sram.sram_inst.SERIAL_MEMORY[5].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                6: u_sram.sram_inst.SERIAL_MEMORY[6].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
                7: u_sram.sram_inst.SERIAL_MEMORY[7].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset] = data;
            endcase
        end
    endtask

    // =========================================================================
    // Backdoor read task
    // =========================================================================
    function [31:0] read_sram_backdoor;
        input [15:0] logical_addr;
        reg [11:0] mapped_addr;
        integer serial_idx;
        integer offset;
        begin
            if (logical_addr[15:12] == 4'h0) begin
                mapped_addr = logical_addr[11:0];
            end else if (logical_addr[15:12] == 4'h1) begin
                mapped_addr = 12'd100 + logical_addr[13:2];
            end else if (logical_addr[15:12] == 4'h2) begin
                mapped_addr = 12'd300 + logical_addr[11:0];
            end else begin
                mapped_addr = logical_addr[11:0];
            end

            serial_idx = mapped_addr[2:0];
            offset = mapped_addr[11:3];

            case (serial_idx)
                0: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[0].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                1: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[1].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                2: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[2].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                3: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[3].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                4: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[4].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                5: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[5].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                6: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[6].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                7: read_sram_backdoor = u_sram.sram_inst.SERIAL_MEMORY[7].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[offset];
                default: read_sram_backdoor = 32'hxxxxxxxx;
            endcase
        end
    endfunction

    // =========================================================================
    // Reset task  
    // =========================================================================
    task reset_dut;
        begin
            rst_n = 0;
            start = 0;
            #200;
            rst_n = 1;
            #100;
        end
    endtask

    // =========================================================================
    // Clear SRAM (set all locations to 0)
    // =========================================================================
    task clear_sram;
        integer addr;
        begin
            for (addr = 0; addr < 512; addr = addr + 1) begin
                u_sram.sram_inst.SERIAL_MEMORY[0].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[1].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[2].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[3].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[4].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[5].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[6].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
                u_sram.sram_inst.SERIAL_MEMORY[7].PARALLEL_MEMORY[0].sky130_sram_2kbyte_1rw1r_32x512_8_i.mem[addr] = 32'd0;
            end
        end
    endtask

    // =========================================================================
    // Setup 5x5 test with kernel and image values
    // =========================================================================
    task setup_5x5_test;
        input [31:0] kernel_row0;
        input [31:0] kernel_row1;
        input [31:0] kernel_row2;
        input [31:0] image_word0;
        input [31:0] image_word1;
        begin
            cfg_img_width = 5;
            cfg_img_height = 5;
            cfg_kernel_size = 2; // 3x3

            // Kernel weights (reverse order for SA loading)
            write_sram_backdoor(16'h000E, kernel_row0);
            write_sram_backdoor(16'h000F, 32'h00000000);
            write_sram_backdoor(16'h000C, kernel_row1);
            write_sram_backdoor(16'h000D, 32'h00000000);
            write_sram_backdoor(16'h000A, kernel_row2);
            write_sram_backdoor(16'h000B, 32'h00000000);

            // Image (5x5) - 5 rows, row spacing = 5 words
            write_sram_backdoor(16'h1000, image_word0);
            write_sram_backdoor(16'h1001, image_word1);
            write_sram_backdoor(16'h1005, image_word0);
            write_sram_backdoor(16'h1006, image_word1);
            write_sram_backdoor(16'h100A, image_word0);
            write_sram_backdoor(16'h100B, image_word1);
            write_sram_backdoor(16'h100F, image_word0);
            write_sram_backdoor(16'h1010, image_word1);
            write_sram_backdoor(16'h1014, image_word0);
            write_sram_backdoor(16'h1015, image_word1);
        end
    endtask

    // =========================================================================
    // Run and verify task
    // =========================================================================
    task run_and_verify;
        input [255:0] test_name;
        input integer expected_count;
        integer idx;
        integer pass_count;
        integer fail_count;
        reg [31:0] actual_val;
        reg [31:0] expected_val;
        begin
            pass_count = 0;
            fail_count = 0;

            $display("\n========================================");
            $display("Running: %s", test_name);
            $display("Config: %0dx%0d image, %0dx%0d kernel", 
                     cfg_img_height, cfg_img_width, 
                     cfg_kernel_size + 1, cfg_kernel_size + 1);
            $display("========================================");

            @(posedge clk);
            start = 1;
            @(posedge clk);
            start = 0;

            // Wait with timeout
            fork
                begin wait(done); end
                begin #100000000; $display("TIMEOUT!"); end
            join_any
            disable fork;

            if (done) begin
                // Let writes settle
                repeat(10) @(posedge clk);

                // Verify
                for (idx = 0; idx < expected_count; idx = idx + 1) begin
                    actual_val = read_sram_backdoor(16'h2000 + idx);
                    expected_val = expected_outputs[idx];

                    if (actual_val == expected_val) begin
                        pass_count = pass_count + 1;
                        $display("  PASS: Output[%0d] = %0d", idx, actual_val);
                    end else begin
                        fail_count = fail_count + 1;
                        $display("  FAIL: Output[%0d] = %0d (expected %0d)", idx, actual_val, expected_val);
                    end
                end
            end

            $display("Result: %0d/%0d passed", pass_count, expected_count);

            if (fail_count == 0) begin
                passed_tests = passed_tests + 1;
                $display(">>> TEST PASSED <<<");
            end else begin
                failed_tests = failed_tests + 1;
                $display(">>> TEST FAILED <<<");
            end

            total_tests = total_tests + 1;
        end
    endtask

    // =========================================================================
    // Main test sequence
    // =========================================================================
    initial begin
        $dumpfile("tb_sram_multi_test.vcd");
        $dumpvars(0, tb_sram_multi_test);

        $display("\n################################################################");
        $display("#  Convolution Accelerator - SRAM Multi-Test Suite            #");
        $display("################################################################\n");

        // Warmup
        $display("Running warmup...");
        reset_dut();
        clear_sram();
        setup_5x5_test(32'h00050505, 32'h00050505, 32'h00050505, 32'h05050505, 32'h00000005);
        @(posedge clk); start = 1; @(posedge clk); start = 0;
        wait(done);
        $display("Warmup complete.\n");

        // =====================================================================
        // TEST 1: 3x3 All Ones, 5x5 All Ones
        // =====================================================================
        reset_dut();
        clear_sram();
        setup_5x5_test(32'h00010101, 32'h00010101, 32'h00010101, 32'h01010101, 32'h00000001);
        num_expected = 9;
        for (i = 0; i < 9; i = i + 1) expected_outputs[i] = 32'd9;
        run_and_verify("3x3 Ones, 5x5 Ones (SRAM)", num_expected);

        // =====================================================================
        // TEST 2: 3x3 Twos, 5x5 Threes
        // =====================================================================
        reset_dut();
        clear_sram();
        setup_5x5_test(32'h00020202, 32'h00020202, 32'h00020202, 32'h03030303, 32'h00000003);
        num_expected = 9;
        for (i = 0; i < 9; i = i + 1) expected_outputs[i] = 32'd54;
        run_and_verify("3x3 Twos, 5x5 Threes (SRAM)", num_expected);

        // =====================================================================
        // TEST 3: tb_custom_5x5 equivalent
        // =====================================================================
        reset_dut();
        clear_sram();
        cfg_img_width = 5;
        cfg_img_height = 5;
        cfg_kernel_size = 2;

        // Kernel from tb_custom_5x5
        write_sram_backdoor(16'h000E, 32'h00CB2C14);
        write_sram_backdoor(16'h000F, 32'h00000000);
        write_sram_backdoor(16'h000C, 32'h00D66698);
        write_sram_backdoor(16'h000D, 32'h00000000);
        write_sram_backdoor(16'h000A, 32'h007927F0);
        write_sram_backdoor(16'h000B, 32'h00000000);

        // Image from tb_custom_5x5
        write_sram_backdoor(16'h1000, 32'h5FE1DC66);
        write_sram_backdoor(16'h1001, 32'h000000B3);
        write_sram_backdoor(16'h1005, 32'h5CCBEA3D);
        write_sram_backdoor(16'h1006, 32'h00000003);
        write_sram_backdoor(16'h100A, 32'h950EF362);
        write_sram_backdoor(16'h100B, 32'h000000F5);
        write_sram_backdoor(16'h100F, 32'h63F46A2E);
        write_sram_backdoor(16'h1010, 32'h000000BB);
        write_sram_backdoor(16'h1014, 32'hC799D447);
        write_sram_backdoor(16'h1015, 32'h000000BC);

        num_expected = 9;
        expected_outputs[0] = 168668; expected_outputs[1] = 186442; expected_outputs[2] = 124715;
        expected_outputs[3] = 140101; expected_outputs[4] = 149473; expected_outputs[5] = 163521;
        expected_outputs[6] = 129335; expected_outputs[7] = 178835; expected_outputs[8] = 211004;

        run_and_verify("tb_custom_5x5 equivalent (SRAM)", num_expected);

        // =====================================================================
        // SUMMARY
        // =====================================================================
        $display("\n################################################################");
        $display("#                    TEST SUMMARY                             #");
        $display("################################################################");
        $display("  Total Tests:  %0d", total_tests);
        $display("  Passed:       %0d", passed_tests);
        $display("  Failed:       %0d", failed_tests);
        $display("################################################################");

        if (failed_tests == 0) begin
            $display("\n  >>> ALL TESTS PASSED! <<<\n");
        end else begin
            $display("\n  >>> SOME TESTS FAILED <<<\n");
        end

        $finish;
    end

endmodule
